prompt --application/pages/page_00001
begin
wwv_flow_imp_page.create_page(
 p_id=>1
,p_name=>'Home'
,p_alias=>'HOME'
,p_step_title=>'LLM Chatbot Dome'
,p_autocomplete_on_off=>'OFF'
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'',
'/* =============================================================================',
'   DOCUMENTATION HEADER',
'   -----------------------------------------------------------------------------',
'   Project         : Oracle APEX 26.1 - Medical Center Management System',
'   Developer       : Malek Al-edresi',
'   Last Updated    : 2026-07-07',
'   Purpose         : Create a responsive, interactive Floating Action Button (FAB)',
unistr('                     positioned at the bottom\2011left corner, with smooth hover,'),
unistr('                     active, and focus\2011visible states for enhanced UX.'),
'   Components      : ',
'                     - .c-floating-bt (core FAB class)',
'                     - :hover state (scale up + shadow intensification)',
'                     - :active state (scale down to simulate press)',
'                     - :focus-visible state (keyboard accessibility outline)',
unistr('   Font Family     : Font Awesome 6 (built\2011in Oracle APEX 26.1) for icons'),
'   Compatibility   : Oracle APEX 26.1 / Chrome / Firefox / Safari / Edge',
'   Instructions    : ',
'                     1. Place this code in (Page Attributes > CSS > Inline) or',
'                        in your application''s external CSS file.',
'                     2. In the button properties, add the class "c-floating-bt"',
'                        to the CSS Classes attribute.',
'                     3. To set an icon, use the "Icon" property in the button',
'                        attributes and enter the icon name (e.g., "fa-plus").',
'   ============================================================================= */',
'',
'/* =============================================================================',
'   1.  Core Floating Action Button (FAB) Rules',
'       ----------------------------------------------------------------------',
'       - Fixed positioning keeps the button visible even when scrolling.',
unistr('       - Dimensions (65\00D765px) with border\2011radius: 50% create a perfect circle.'),
'       - Flexbox ensures the icon is perfectly centered both vertically and',
'         horizontally.',
'   ============================================================================= */',
'.c-floating-bt {',
'    /* ----- 1.1  Positioning  ----- */',
'    position: fixed !important;   /* Fixed relative to the viewport */',
'    bottom: 30px !important;      /* Distance from the bottom edge */',
