'    z-index: 9999 !important;     /* Appear above all other page elements */',
'',
'    /* ----- 1.2  Shape & Size  ----- */',
'    height: 65px !important;      /* Height */',
'    width: 65px !important;       /* Width (equal to height for a perfect circle) */',
'    border-radius: 50% !important; /* Fully rounded corners */',
'    border: none !important;      /* Remove default button borders */',
'',
'    /* ----- 1.3  Inner Content Alignment (Flexbox)  ----- */',
'    display: flex !important;            /* Enable flexbox layout */',
'    align-items: center !important;      /* Vertically center the icon */',
'    justify-content: center !important;  /* Horizontally center the icon */',
'    font-size: 2rem !important;          /* Icon size (relative to root font) */',
'',
'    /* ----- 1.4  Colors & Background  ----- */',
'    /* Modern gradient from deep blue to purple for a sleek appearance */',
'    background: linear-gradient(135deg, #2563eb, #7c3aed) !important;',
'    color: #ffffff !important;            /* Icon colour (white) for high contrast */',
'',
'    /* ----- 1.5  Shadow & Elevation  ----- */',
unistr('    /* Soft blue\2011toned shadow gives a floating, 3D effect */'),
'    box-shadow: 0 8px 25px rgba(37, 99, 235, 0.4) !important;',
'',
'    /* ----- 1.6  Transitions for Smooth Interactions  ----- */',
'    /* All changes (scale, shadow, background) animate over 0.25s with an ease curve */',
'    transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1) !important;',
'',
'    /* ----- 1.7  User Experience Enhancements  ----- */',
'    user-select: none !important; /* Prevent accidental text selection inside the button */',
'    cursor: pointer !important;   /* Change cursor to pointer on hover */',
'}',
'',
'/* =============================================================================',
'   2.  Hover State',
'       ----------------------------------------------------------------------',
'       - Triggered when the mouse pointer is over the button.',
'       - Scales up slightly (1.12x) to attract attention.',
