'   ============================================================================= */',
'.c-floating-bt:hover {',
'    transform: scale(1.12) !important;          /* Slight enlargement */',
'    box-shadow: 0 12px 35px rgba(37, 99, 235, 0.6) !important; /* Deeper shadow */',
'    background: linear-gradient(135deg, #1d4ed8, #6d28d9) !important; /* Darker gradient */',
'}',
'',
'/* =============================================================================',
